import{_ as e,a as n,b as i,c as d,d as t,e as l,f as o,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as p,c as u,a2 as h}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/federated-distributed-index.md","filePath":"ms-MY/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),c={name:"ms-MY/Other/federated-distributed-index.md"};function m(b,a,k,g,f,y){return p(),u("div",null,[...a[0]||(a[0]=[h('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index membolehkan beberapa ImgBed sites berkongsi file lists antara satu sama lain.</p><p>Secara ringkas:</p><ul><li>Anda boleh share selected folders daripada site anda dengan orang lain.</li><li>Anda boleh join node lain dan sync shared file list node itu ke admin panel anda.</li><li>Federated files terutama untuk browsing, searching dan membuka links. Ia tidak di-upload semula ke storage anda sendiri.</li></ul><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+e+`" alt="Local federation node" loading="lazy"></p><p>Halaman ini mempunyai tiga tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>Enable node anda, confirm public domain, pilih shared folders dan update outbound index</td></tr><tr><td>Nodes I Joined</td><td>Manage ImgBed nodes lain yang anda joined</td></tr><tr><td>Nodes Joining Me</td><td>Manage requests daripada orang lain yang mahu join node anda</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>Buka <code>Local Node</code>.</li><li>Hidupkan <code>Enable</code>.</li><li>Pilih folders untuk share di bawah <code>Sync folders</code>.</li><li>Klik <code>Update Outbound Index</code>.</li><li>Jika ImgBed detect domain change, confirm current domain betul sebelum meneruskan.</li></ol><p>Anda boleh memilih beberapa sync folders.</p><p>Jika sync folder list kosong, semua folders akan dishare.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain ialah site URL yang digunakan oleh nodes lain untuk mengakses node anda.</p><p>ImgBed detect ini secara automatik. Anda tidak perlu menaip secara manual. Kali pertama update index, ImgBed bertanya sama ada current access URL ialah production domain.</p><p>Jika domain berubah kemudian, update index akan meminta confirmation sekali lagi.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders menentukan files mana yang dishare dengan federation nodes.</p><p>Contohnya, jika anda hanya memilih:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Nodes lain hanya dapat melihat files dalam dua directories tersebut.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Ini update file list yang nodes lain boleh sync daripada anda.</p><p>Gunakan apabila:</p><ul><li>Anda enable federation buat kali pertama.</li><li>Anda upload files yang mahu dishare.</li><li>Anda menukar sync folders.</li><li>Anda menukar public domain dan perlu confirm.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> ialah tempat anda subscribe nodes lain.</p><p><img src="`+n+'" alt="Nodes I joined" loading="lazy"></p><h3 id="request-untuk-join-node-lain" tabindex="-1">Request Untuk Join Node Lain <a class="header-anchor" href="#request-untuk-join-node-lain" aria-label="Permalink to &quot;Request Untuk Join Node Lain&quot;">​</a></h3><ol><li>Minta invitation link daripada owner sebelah sana.</li><li>Paste ke input box.</li><li>Klik <code>Request to Join</code>.</li><li>Tunggu owner sebelah sana approve dalam admin panel mereka.</li></ol><p>Selepas approval, node status menjadi approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> sync file lists daripada nodes yang anda joined.</p><p>Gunakan apabila:</p><ul><li>Owner sebelah sana baru approve request anda.</li><li>Owner sebelah sana memberitahu shared content telah update.</li><li>Anda mahu refresh semua joined federation file lists.</li></ul><p>Untuk update satu node sahaja, klik <code>Update Index</code> pada node card tersebut.</p><p><img src="'+i+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>Jika tidak mahu sync node lagi, klik <code>Unsubscribe</code>.</p><p>Selepas unsubscribe, federated index node itu dibuang daripada local site anda.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> ialah tempat mengurus requests daripada orang lain.</p><p><img src="'+d+'" alt="Nodes joining me" loading="lazy"></p><h3 id="generate-invitation-link" tabindex="-1">Generate Invitation Link <a class="header-anchor" href="#generate-invitation-link" aria-label="Permalink to &quot;Generate Invitation Link&quot;">​</a></h3><ol><li>Pastikan local node enabled.</li><li>Klik <code>Update Outbound Index</code> sekurang-kurangnya sekali supaya ImgBed confirm public domain.</li><li>Buka <code>Nodes Joining Me</code>.</li><li>Klik <code>Reset Invitation Link</code>.</li><li>Copy invitation link dan hantar kepada owner sebelah sana.</li></ol><p>Jika invitation link kosong, biasanya public domain belum disahkan. Kembali ke <code>Local Node</code> dan klik <code>Update Outbound Index</code>.</p><h3 id="handle-join-requests" tabindex="-1">Handle Join Requests <a class="header-anchor" href="#handle-join-requests" aria-label="Permalink to &quot;Handle Join Requests&quot;">​</a></h3><p>Apabila seseorang submit request, ia muncul dalam list <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>Membenarkan node sebelah sana sync shared file list anda</td></tr><tr><td>Reject</td><td>Menolak join request</td></tr><tr><td>Delete</td><td>Membuang finished record</td></tr><tr><td>Check Status</td><td>Menyemak sama ada sebelah sana masih mengekalkan relationship ini</td></tr></tbody></table><p>Selepas approval, sebelah sana masih perlu klik <code>Update Inbound Index</code> sebelum shared files anda muncul di sana.</p><p><img src="'+t+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>Selepas relationship approved, klik <code>Message</code> pada node card.</p><p>Messages hanya untuk komunikasi tentang federation relationship. Ia tidak mengubah files, tags, directories atau permissions.</p><p><img src="'+l+'" alt="Messages" loading="lazy"></p><h2 id="melihat-federated-files" tabindex="-1">Melihat Federated Files <a class="header-anchor" href="#melihat-federated-files" aria-label="Permalink to &quot;Melihat Federated Files&quot;">​</a></h2><p>Selepas sync selesai, kembali ke admin file list.</p><p>Di bahagian atas halaman, switch antara local files dan federated files. Dalam federated files, anda boleh browse synced content.</p><p>Federated files terutama untuk viewing, searching, previewing dan copying links. Ia bukan local files, jadi anda tidak boleh move, delete, retag atau back up daripada site anda sendiri.</p><p><img src="'+o+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="mengapa-ia-meminta-reapply-kerana-tiada-relationship-record" tabindex="-1">Mengapa Ia Meminta Reapply Kerana Tiada Relationship Record? <a class="header-anchor" href="#mengapa-ia-meminta-reapply-kerana-tiada-relationship-record" aria-label="Permalink to &quot;Mengapa Ia Meminta Reapply Kerana Tiada Relationship Record?&quot;">​</a></h3><p>Ini biasanya bermaksud sebelah sana delete anda dan membuang record, jadi relationship tidak lagi ditemui. Submit join request baharu.</p><p><img src="'+s+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="mengapa-saya-tidak-nampak-files-selepas-join" tabindex="-1">Mengapa Saya Tidak Nampak Files Selepas Join? <a class="header-anchor" href="#mengapa-saya-tidak-nampak-files-selepas-join" aria-label="Permalink to &quot;Mengapa Saya Tidak Nampak Files Selepas Join?&quot;">​</a></h3><p>Semak:</p><ol><li>Owner sebelah sana telah approve request anda.</li><li>Owner sebelah sana telah klik <code>Update Outbound Index</code>.</li><li>Anda telah klik <code>Update Inbound Index</code>.</li><li>Sync folders owner sebelah sana termasuk directories yang mahu mereka share.</li></ol><h3 id="apa-perlu-dibuat-apabila-domain-change-dikesan" tabindex="-1">Apa Perlu Dibuat Apabila Domain Change Dikesan? <a class="header-anchor" href="#apa-perlu-dibuat-apabila-domain-change-dikesan" aria-label="Permalink to &quot;Apa Perlu Dibuat Apabila Domain Change Dikesan?&quot;">​</a></h3><p>Jika anda sedang membuka admin panel melalui production domain, confirm dan teruskan.</p><p>Jika menggunakan temporary address, cancel, buka semula admin panel menggunakan production domain, kemudian cuba lagi.</p><h3 id="apa-maksud-empty-sync-folder-list" tabindex="-1">Apa Maksud Empty Sync Folder List? <a class="header-anchor" href="#apa-maksud-empty-sync-folder-list" aria-label="Permalink to &quot;Apa Maksud Empty Sync Folder List?&quot;">​</a></h3><p>Empty sync folder list bermaksud semua folders dishare.</p><p>Untuk share directories tertentu sahaja, pilih folders tersebut secara manual.</p><h3 id="perbezaan-outbound-dan-inbound-index-updates" tabindex="-1">Perbezaan Outbound dan Inbound Index Updates <a class="header-anchor" href="#perbezaan-outbound-dan-inbound-index-updates" aria-label="Permalink to &quot;Perbezaan Outbound dan Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Update apa yang orang lain boleh sync daripada saya</td></tr><tr><td>Update Inbound Index</td><td>Update apa yang saya sync daripada orang lain</td></tr></tbody></table>',78)])])}const _=r(c,[["render",m]]);export{I as __pageData,_ as default};
